import{c as t,cN as e,cG as d,cb as n,c8 as a,cf as r,cT as s,ce as o,cg as i}from"./chunks/framework.BlkIsu1j.js";const l=JSON.parse('{"title":"Claude Code 培训指南","description":"","frontmatter":{"title":"Claude Code 培训指南","outline":"deep","layout":"doc","prev":false,"next":"/ai/claudecode/01-installation","date":"2026-05-20T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecode/index.md","filePath":"ai/claudecode/index.md","lastUpdated":1780059183000}'),h={id:"frontmatter-title",tabindex:"-1"};const c=t({name:"ai/claudecode/index.md"},[["render",function(t,l,c,g,p,C){const u=e("vitepress-mermaid");return d(),n("div",null,[a("h1",h,[r(s(t.$frontmatter.title)+" ",1),l[0]||(l[0]=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),l[1]||(l[1]=o('<h2 id="什么是-claude-code" tabindex="-1">什么是 Claude Code <a class="header-anchor" href="#什么是-claude-code" aria-label="Permalink to “什么是 Claude Code”">​</a></h2><p>Claude Code 是 Anthropic 推出的一款 <strong>Agentic Coding 工具</strong>。与传统 AI 代码补全（如 GitHub Copilot）不同，它不只是给出一行建议，而是像一个真正的工程师一样：<strong>读懂你的项目、自主操作文件、执行终端命令、管理 Git 工作流</strong>——全程与你对话协作。</p><p>它的核心定位是一个 <strong>命令行/IDE 层的 AI Agent</strong>，而非代码补全插件。你可以把它理解为：一个驻扎在你终端里的、会写代码的同事。</p><h2 id="核心概念-agent-与模型" tabindex="-1">核心概念：Agent 与模型 <a class="header-anchor" href="#核心概念-agent-与模型" aria-label="Permalink to “核心概念：Agent 与模型”">​</a></h2><p>初次接触 Claude Code 时，最容易混淆的是 <strong>Agent</strong> 和 <strong>模型</strong> 的关系。理清这两个概念，才能正确理解 Claude Code 的工作方式。</p><h3 id="claude-code-是什么" tabindex="-1">Claude Code 是什么？ <a class="header-anchor" href="#claude-code-是什么" aria-label="Permalink to “Claude Code 是什么？”">​</a></h3><p><strong>Claude Code 是一个 Agent</strong>——它是一个软件框架/工具，负责：</p><ul><li>管理你和 AI 模型之间的对话</li><li>调用工具（读文件、写代码、执行命令、搜索网络等）</li><li>控制权限（决定何时需要你的确认）</li><li>维护上下文（CLAUDE.md、Memory、对话历史）</li><li>协调多个模型的调度</li></ul>',8)),i(u,{value:'flowchart TB\n    subgraph SHELLS["🖥️ Shell / Client Layer (使用界面)"]\n        direction TB\n        E1["📟 CLI<br>(终端命令行)"]\n        E2["🌐 Web UI<br>(claude.ai/code)"]\n        E3["💻 VSCode 扩展<br>(推荐)"]\n        E4["🧩 JetBrains 插件<br>(IntelliJ/PyCharm)"]\n        E5["🖲️ Desktop App<br>(独立应用)"]\n    end\n\n    SHELLS --\x3e AGENT\n\n    subgraph AGENT["Claude Code (Agent)"]\n        direction LR\n\n        subgraph CORE["🧠 Core Runtime"]\n            direction TB\n            A1["对话 / 规划"]\n            A2["工具编排"]\n            A3["权限与安全控制"]\n            A4["上下文管理<br>(CLAUDE.md / Memory)"]\n            A5["会话管理<br>(Save / Resume)"]\n        end\n\n        subgraph TOOLS["🔧 工具系统"]\n            direction TB\n            B1["文件系统"]\n            B2["终端 / Shell"]\n            B3["Git 集成"]\n            B4["Web 搜索 / 获取"]\n            B5["MCP 服务器"]\n            B6["网络请求"]\n            B7["图像 / PDF 读取"]\n        end\n\n        subgraph EXT["🧩 扩展生态"]\n            direction TB\n            C1["Skills<br>(技能 / 工作流)"]\n            C2["Plugins<br>(MCP 插件)"]\n            C3["Hooks<br>(事件钩子)"]\n            C4["斜杠命令<br>(/help 等)"]\n            C5["键盘快捷键<br>(Keymap)"]\n        end\n    end\n\n    AGENT --\x3e API["调用模型 API"]\n\n    subgraph MODELS["🤖 模型层"]\n        direction TB\n        subgraph OFFICIAL["Anthropic 官方模型"]\n            D1["Claude Opus 4.7"]\n            D2["Claude Sonnet 4.6"]\n            D3["Claude Haiku 4.5"]\n        end\n        D4["第三方模型<br>(DeepSeek / OpenAI 等)"]\n    end\n\n    API --\x3e OFFICIAL\n    API -. 通过 cc-switch 接入 .-> D4'}),l[2]||(l[2]=o('<h3 id="claude-模型家族" tabindex="-1">Claude 模型家族 <a class="header-anchor" href="#claude-模型家族" aria-label="Permalink to “Claude 模型家族”">​</a></h3><p><strong>模型是 Agent 的&quot;大脑&quot;</strong>——它提供理解和生成代码的智能。Anthropic 提供三个等级的模型：</p><table tabindex="0"><thead><tr><th>模型</th><th>定位</th><th>特点</th><th>适用场景</th><th style="text-align:center;">总结</th></tr></thead><tbody><tr><td><strong>Claude Opus 4.7</strong></td><td>旗舰级</td><td>最强推理、最深理解、最准代码</td><td>复杂架构设计、深度调试、跨文件大规模重构</td><td style="text-align:center;">强</td></tr><tr><td><strong>Claude Sonnet 4.6</strong></td><td>主力级</td><td>性能与速度的最佳平衡</td><td>日常编程、Bug 修复、功能开发（推荐默认使用）</td><td style="text-align:center;">平衡模式</td></tr><tr><td><strong>Claude Haiku 4.5</strong></td><td>轻量级</td><td>最快响应、最低成本</td><td>简单查询、代码格式化、文档整理</td><td style="text-align:center;">快</td></tr></tbody></table><p>三者使用完全相同的 Agent 框架和工具系统，区别仅在于推理能力和速度。</p><h3 id="agent-与模型的关系" tabindex="-1">Agent 与模型的关系 <a class="header-anchor" href="#agent-与模型的关系" aria-label="Permalink to “Agent 与模型的关系”">​</a></h3><h4 id="一个简单的类比" tabindex="-1"><strong>一个简单的类比：</strong> <a class="header-anchor" href="#一个简单的类比" aria-label="Permalink to “一个简单的类比：”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Agent = 汽车（方向盘、油门、刹车、导航）</span></span>\n<span class="line"><span>模型  = 发动机（提供动力）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>换模型 ≈ 换发动机（同样的车，不同的马力）</span></span>\n<span class="line"><span>Agent 的能力 ≠ 模型的智能（是两者的乘积）</span></span></code></pre></div><p>具体来说：</p><ul><li><strong>Agent 决定&quot;能做什么&quot;</strong>：能读什么文件、能执行哪些命令、能否搜索网络、何时需要你确认——这些都是 Agent 层面的事，与使用哪个模型无关。</li><li><strong>模型决定&quot;做得有多好&quot;</strong>：代码质量、逻辑推理深度、对复杂需求的理解——这些取决于模型能力。Opus 写的代码可能比 Haiku 更优雅，但它们用的都是同一套工具。</li><li><strong>你可以随时切换模型</strong>：通过 cc-switch 在不同模型间切换（甚至接入 DeepSeek 等第三方模型），Agent 的行为框架保持不变，但输出质量会随模型而变化。</li></ul><h4 id="为什么这个区别很重要" tabindex="-1"><strong>为什么这个区别很重要？</strong> <a class="header-anchor" href="#为什么这个区别很重要" aria-label="Permalink to “为什么这个区别很重要？”">​</a></h4><p>理解 Agent 和模型的分离，能帮你做出更好的决策：</p><ul><li><strong>Agent 行为出问题</strong>（如改错文件、没读上下文）→ 检查 CLAUDE.md、对话状态、权限配置，换模型没用</li><li><strong>输出质量出问题</strong>（如代码不够好、逻辑不严谨）→ 切换到更强的模型（Sonnet → Opus）</li><li><strong>想省钱但 Agent 能力不受影响</strong>→ 日常用 Haiku/Sonnet，复杂任务切 Opus</li></ul><h2 id="平台生态" tabindex="-1">平台生态 <a class="header-anchor" href="#平台生态" aria-label="Permalink to “平台生态”">​</a></h2><p>产品列表：</p><table tabindex="0"><thead><tr><th>产品</th><th>平台</th><th>安装/访问方式</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Claude Code CLI</strong></td><td>终端 / SSH</td><td><code>npm install -g @anthropic-ai/claude-code</code></td><td>远程服务器、无 GUI 环境、自动化脚本</td></tr><tr><td><strong>Claude Code for VSCode</strong> ⭐</td><td>VSCode</td><td>扩展市场搜索 &quot;Claude Code&quot;</td><td><strong>日常首选</strong> — IDE 深度集成，Diff 预览，侧边栏对话</td></tr><tr><td><strong>JetBrains 插件</strong></td><td>IntelliJ / PyCharm / WebStorm</td><td>插件市场搜索 &quot;Claude Code&quot;</td><td>JetBrains 用户的 IDE 内体验</td></tr><tr><td><strong>Web 界面</strong></td><td>浏览器</td><td>claude.ai/code</td><td>快速试用、临时任务、无需安装</td></tr><tr><td><strong>Desktop 应用</strong></td><td>macOS / Windows</td><td>官网下载</td><td>独立桌面窗口，无需浏览器</td></tr></tbody></table><p>Claude Code 支持多个平台，其中 <strong>VSCode 扩展</strong>是体验最完整的形态：</p><h3 id="claude-code-cli-功能最全的client" tabindex="-1">Claude Code CLI （功能最全的Client） <a class="header-anchor" href="#claude-code-cli-功能最全的client" aria-label="Permalink to “Claude Code CLI （功能最全的Client）”">​</a></h3><p>Claude Code CLI 是 Anthropic 提供的命令行原生交互方式，通过 npm 全局安装后即可在终端中使用。它拥有与 VSCode 扩展完全一致的能力，所有交互通过纯文本终端完成。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>适用场景：</strong></p><ul><li><strong>SSH 远程服务器</strong>：在开发机上无 GUI 环境时，CLI 是唯一选择</li><li><strong>自动化 &amp; CI/CD</strong>：可通过非交互模式集成到脚本和流水线中</li><li><strong>习惯终端的开发者</strong>：Vim/Neovim/Emacs 用户、tmux 工作流</li><li><strong>轻量快速启动</strong>：无需打开 IDE，终端中直接 <code>claude</code> 即可开始对话</li></ul><p><strong>与 VSCode 扩展的差异：</strong></p><table tabindex="0"><thead><tr><th>方面</th><th>CLI</th><th>VSCode 扩展</th></tr></thead><tbody><tr><td>交互界面</td><td>终端纯文本</td><td>侧边栏面板 + 编辑器 Diff</td></tr><tr><td>Diff 审查</td><td>纯文本 diff</td><td>内联双栏 Diff 预览，逐文件 Accept/Reject</td></tr><tr><td>文件上下文</td><td>手动指定或靠对话上下文</td><td>自动感知打开的文件和选中文本</td></tr><tr><td>安装方式</td><td><code>npm install -g</code></td><td>VSCode 扩展市场安装</td></tr></tbody></table><p>CLI 的 Diff 回退体验虽然不如 VSCode 扩展直观，但在远程开发和自动化场景中不可替代。建议本地开发使用 VSCode 扩展，远程/自动化场景使用 CLI。</p><h3 id="claude-code-for-vscode-推荐" tabindex="-1">Claude Code for VSCode（推荐） <a class="header-anchor" href="#claude-code-for-vscode-推荐" aria-label="Permalink to “Claude Code for VSCode（推荐）”">​</a></h3><p>VSCode 扩展是目前体验最完整、社区使用率最高的方式。它在 VSCode 侧边栏中嵌入完整的 Claude Code 终端，并与 VSCode 的 IDE 能力深度融合。</p><p><strong>核心交互模式：</strong></p><table tabindex="0"><thead><tr><th>交互方式</th><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>侧边栏对话</strong></td><td><code>Cmd+Shift+L</code> 打开面板</td><td>主交互区，支持多轮对话、文件 Diff、终端输出</td></tr><tr><td><strong>内联编辑</strong></td><td><code>Cmd+Shift+I</code> 打开输入框</td><td>光标处直接输入指令，结果内联展示在代码旁边</td></tr><tr><td><strong>右键菜单</strong></td><td>选中代码 → 右键</td><td>快速触发 &quot;Ask Claude&quot; &quot;Explain Code&quot; &quot;Fix This&quot; 等</td></tr><tr><td><strong>选中即上下文</strong></td><td>选中代码后提问</td><td>Claude 自动将选中内容作为上下文，无需手动粘贴</td></tr></tbody></table><p><strong>IDE 深度集成能力：</strong></p><ul><li><strong>内联 Diff 预览</strong>：所有代码修改以双栏 Diff 形式呈现，逐文件审查，一键 Accept/Reject</li><li><strong>终端集成</strong>：Claude 执行命令的输出实时显示在 VSCode 终端中，支持中断和重试</li><li><strong>文件感知</strong>：自动感知当前打开的文件、光标位置、选中文本，无需手动指定上下文</li><li><strong>诊断信息感知</strong>：能读取 VSCode 的错误提示、警告、lint 结果，辅助修复</li><li><strong>快捷键体系</strong>：完整的快捷键绑定，常用操作无需离开键盘</li><li><strong>跨文件编辑预览</strong>：多文件变更统一展示，查看整体改动后再决定是否接受</li></ul><p><strong>为什么 VSCode 扩展是最佳选择？</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CLI:          对话在终端，Diff 在终端 —— 纯文本，但缺少图形化审查</span></span>\n<span class="line"><span>VSCode 扩展:   对话在侧边栏，Diff 在编辑器 —— 可视化变更，所见即所得</span></span></code></pre></div><p>对于代码审查、多文件重构、UI 开发等需要可视化反馈的场景，VSCode 扩展的 Diff 视图远胜于终端的纯文本 diff。</p><p>本指南以 VSCode 扩展为主要介绍对象，大部分功能在不同平台通用。</p><h3 id="快捷键一览" tabindex="-1">快捷键一览 <a class="header-anchor" href="#快捷键一览" aria-label="Permalink to “快捷键一览”">​</a></h3><p>常用快捷键的 Mac / Windows 对照：</p><table tabindex="0"><thead><tr><th>操作</th><th>Mac</th><th>Windows / Linux</th></tr></thead><tbody><tr><td><strong>打开/聚焦侧边栏</strong></td><td><code>Cmd+Shift+L</code></td><td><code>Ctrl+Shift+L</code></td></tr><tr><td><strong>内联编辑</strong></td><td><code>Cmd+Shift+I</code></td><td><code>Ctrl+Shift+I</code></td></tr><tr><td><strong>提交新消息</strong></td><td><code>Enter</code></td><td><code>Enter</code></td></tr><tr><td><strong>换行（不提交）</strong></td><td><code>Shift+Enter</code></td><td><code>Shift+Enter</code></td></tr><tr><td><strong>中断 AI 响应</strong></td><td><code>Ctrl+C</code></td><td><code>Ctrl+C</code></td></tr><tr><td><strong>打开快捷键设置</strong></td><td><code>Cmd+K Cmd+S</code></td><td><code>Ctrl+K Ctrl+S</code></td></tr><tr><td><strong>全屏侧边栏</strong></td><td><code>Ctrl+Shift+J</code></td><td><code>Ctrl+Shift+J</code></td></tr><tr><td><strong>选中代码 → 问 Claude</strong></td><td><code>Cmd+I</code></td><td><code>Ctrl+I</code></td></tr><tr><td><strong>审批上一个 Diff</strong></td><td><code>Cmd+Enter</code></td><td><code>Ctrl+Enter</code></td></tr><tr><td><strong>拒绝当前变更</strong></td><td><code>Cmd+Delete</code></td><td><code>Ctrl+Delete</code></td></tr><tr><td><strong>切换主题 (深色/浅色)</strong></td><td><code>Cmd+K Cmd+T</code></td><td><code>Ctrl+K Ctrl+T</code></td></tr><tr><td><strong>打开设置</strong></td><td><code>Cmd+,</code></td><td><code>Ctrl+,</code></td></tr></tbody></table><blockquote><p>提示：你可以通过 VSCode 的 <strong>Keyboard Shortcuts</strong> 设置页面搜索 &quot;Claude&quot; 来自定义所有快捷键绑定。</p></blockquote><h3 id="jetbrains-插件" tabindex="-1">JetBrains 插件 <a class="header-anchor" href="#jetbrains-插件" aria-label="Permalink to “JetBrains 插件”">​</a></h3><p>面向 IntelliJ / PyCharm / WebStorm 用户，体验与 VSCode 扩展类似，提供侧边栏面板和内联 Diff。</p><h3 id="web-界面" tabindex="-1">Web 界面 <a class="header-anchor" href="#web-界面" aria-label="Permalink to “Web 界面”">​</a></h3><p>通过 claude.ai/code 直接使用，无需安装任何软件。适合快速试用或临时任务。</p><h2 id="核心理念-agentic-coding" tabindex="-1">核心理念：Agentic Coding <a class="header-anchor" href="#核心理念-agentic-coding" aria-label="Permalink to “核心理念：Agentic Coding”">​</a></h2><p>理解 Claude Code，关键在于理解 <strong>Agentic Coding</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>传统开发：你写代码 → AI 给建议 → 你决定是否采纳</span></span>\n<span class="line"><span>Agentic Coding：你描述需求 → AI 自主调研 → AI 执行操作 → 你 Review 结果</span></span></code></pre></div><p>这意味着你的角色从 <strong>写代码的人</strong> 变成了 <strong>定义方向 + 审查结果的人</strong>。Claude Code 帮你处理中间的执行细节。</p><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to “学习路径”">​</a></h2><p>本指南按渐进顺序组织，建议按序阅读：</p><ol><li><strong><a href="./01-installation.html">安装与设置</a></strong> — 安装配置，使用 cc-switch 切换模型</li><li><strong><a href="./02-how-it-works.html">工作原理</a></strong> — 理解 Agent Loop 和工具系统</li><li><strong><a href="./03-core-features.html">核心功能</a></strong> — 从基础对话到高级 MCP 扩展</li><li><strong><a href="./04-ecosystem.html">生态与社区</a></strong> — Skills、Plugins、CLAUDE.md 编写规范</li><li><strong><a href="./05-workflows.html">实战工作流</a></strong> — 真实项目场景中的使用模式</li><li><strong><a href="./06-mindset.html">角色转变与局限</a></strong> — 使用后的思考和注意事项</li><li><strong><a href="./cheatsheet.html">Cheatsheet</a></strong> — 常用命令与快捷键速查</li></ol><p>如果你已经完成安装，可以直接跳转到 <a href="./03-core-features.html">核心功能</a> 开始实战。</p>',50))])}]]);export{l as __pageData,c as default};
